import functools

def my_decorator(func):
    @functools.wraps(func)  # Copy metadata from func to wrapper
    def wrapper(*args, **kwargs):
        return func(*args, **kwargs)
    return wrapper

@my_decorator
def greet(name):
    """Greet someone."""
    return f"Hello, {name}"

print(greet.__name__)  # "greet" - Correct!
print(greet.__doc__)   # "Greet someone." - Preserved!

def repeat(n):           # Level 1: Takes decorator args
    def decorator(func):  # Level 2: Takes function
        @functools.wraps(func)
        def wrapper(*args, **kwargs):  # Level 3: Takes function args
            for _ in range(n):
                result = func(*args, **kwargs)
            return result
        return wrapper
    return decorator

@repeat(3)
def say_hello():
    print("Hello!")

say_hello()  # Prints "Hello!" three times

def retry(func=None, *, times=3, delay=1):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(times):
                try:
                    return func(*args, **kwargs)
                except Exception:
                    if attempt < times - 1:
                        time.sleep(delay)
            raise
        return wrapper

    if func is None:
        return decorator  # Called with arguments
    return decorator(func)  # Called without arguments

# Both work:
@retry
def func1(): ...

@retry(times=5, delay=2)
def func2(): ...

import functools
import time

def rate_limit(calls_per_second):
    """Decorator to limit how often a function can be called."""
    min_interval = 1.0 / calls_per_second
    last_call = [0.0]  # Mutable to persist across calls

    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            elapsed = time.time() - last_call[0]
            if elapsed < min_interval:
                time.sleep(min_interval - elapsed)
            last_call[0] = time.time()
            return func(*args, **kwargs)
        return wrapper
    return decorator

@rate_limit(2)  # Max 2 calls per second
def api_call():
    print(f"Called at {time.time():.2f}")

class CountCalls:
    def __init__(self, func):
        functools.update_wrapper(self, func)
        self.func = func
        self.count = 0

    def __call__(self, *args, **kwargs):
        self.count += 1
        print(f"Call #{self.count}")
        return self.func(*args, **kwargs)

@CountCalls
def greet(name):
    return f"Hello, {name}"

greet("Alice")  # Call #1
greet("Bob")    # Call #2
print(greet.count)  # 2

def singleton(cls):
    instances = {}

    @functools.wraps(cls)
    def get_instance(*args, **kwargs):
        if cls not in instances:
            instances[cls] = cls(*args, **kwargs)
        return instances[cls]

    return get_instance

