print(f"Shallow: {sys.getsizeof(data)} bytes")
print(f"Deep:    {deep_getsizeof(data)} bytes")

class TreeNode:
    def __init__(self, value):
        self.value = value
        self.parent = None
        self.children = []

    def add_child(self, child):
        self.children.append(child)
        child.parent = self  # Creates parent ↔ child cycle

    def detach(self):
        """Break the cycle explicitly."""
        if self.parent:
            self.parent.children.remove(self)
            self.parent = None

# Explicit cleanup is faster than waiting for GC
node = TreeNode("leaf")
node.detach()  # Reference counting can now free it immediately

