from collections import deque

def list_queue(n=10_000):
    q = list(range(n))
    while q:
        q.pop(0)  # O(n) shift each time

def deque_queue(n=10_000):
    q = deque(range(n))
    while q:
        q.popleft()  # O(1) each time

